// Build health check prompt based on system type
const input = $input.first().json;

const { id, name, ip, type, ssh_user, ssh_password } = input;

const PROXMOX_HOST = '10.1.1.100';
const isLXC = type === 'lxc';

// Build commands based on type
let exec_prefix;
if (isLXC) {
  exec_prefix = `pct exec ${id} --`;
} else {
  exec_prefix = `ssh ${ssh_user}@${ip}`;
}

const health_commands = [
  // Disk usage
  `${exec_prefix} df -h --output=pcent,target | tail -n +2 | sort -rn`,
  // Memory
  `${exec_prefix} free -m | grep Mem`,
  // CPU load
  `${exec_prefix} cat /proc/loadavg`,
  // Failed services
  `${exec_prefix} systemctl --failed --no-legend 2>/dev/null | head -20 || true`,
  // Critical processes
  `${exec_prefix} ps aux --sort=-%mem | head -5 2>/dev/null || true`
];

const connection_info = isLXC
  ? `Use SSH to connect to Proxmox host ${PROXMOX_HOST} as root, then use pct exec ${id} -- <command> for each check.`
  : `Use SSH to connect directly to ${ip} as ${ssh_user}.`;

const prompt = `You are a Linux system administrator performing a health check on: ${name} (${type}, ${ip || 'LXC'}).

${connection_info}

Execute these health checks:
1. Disk usage: df -h --output=pcent,target | tail -n +2 | sort -rn | head -10
2. Memory: free -m
3. CPU load average: cat /proc/loadavg
4. Failed services: systemctl --failed --no-legend 2>/dev/null | head -20
5. Top memory consumers: ps aux --sort=-%mem | head -5 2>/dev/null

Analyze results and determine health status:
- "ok": disk < 80%, memory < 85%, load < cores*2, no failed services
- "warning": disk 80-90% OR memory 85-95% OR load high OR some non-critical failed services
- "critical": disk > 90% OR memory > 95% OR load very high OR critical services failed

Respond ONLY with valid JSON:
{
  "health_status": "ok|warning|critical",
  "disk_usage_pct": <highest disk usage percentage as integer>,
  "memory_usage_pct": <used/total*100 as integer>,
  "cpu_load": <1-minute load average as float>,
  "services_ok": true|false,
  "failed_services": ["<service name>"],
  "disk_details": [{"mount": "/", "usage_pct": 45}],
  "recommendations": ["<actionable recommendation>"]
}`;

const system_prompt = 'You are an expert Linux system administrator. Perform health checks and respond ONLY with valid JSON. No markdown, no code blocks.';

return [{
  json: {
    id, name, ip, type, ssh_user, ssh_password,
    prompt,
    system_prompt,
    is_lxc: isLXC,
    checked_at: new Date().toISOString()
  }
}];

// Parse health check result
const response = $input.first().json;
const promptData = $('🔧 Build Health Check Prompt').first().json;

let health_status = 'warning';
let disk_usage_pct = 0;
let memory_usage_pct = 0;
let cpu_load = 0;
let services_ok = true;
let failed_services = [];
let disk_details = [];
let recommendations = [];
let parse_error = null;

try {
  const content = response.choices?.[0]?.message?.content || '{}';
  // Clean up markdown if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    health_status = parsed.health_status || 'warning';
    disk_usage_pct = parsed.disk_usage_pct || 0;
    memory_usage_pct = parsed.memory_usage_pct || 0;
    cpu_load = parsed.cpu_load || 0;
    services_ok = parsed.services_ok !== undefined ? parsed.services_ok : true;
    failed_services = parsed.failed_services || [];
    disk_details = parsed.disk_details || [];
    recommendations = parsed.recommendations || [];
  }
} catch (e) {
  parse_error = e.message;
  health_status = 'warning';
}

return [{
  json: {
    name: promptData.name,
    id: promptData.id,
    type: promptData.type,
    ip: promptData.ip,
    health_status,
    disk_usage_pct,
    memory_usage_pct,
    cpu_load,
    services_ok,
    failed_services,
    disk_details,
    recommendations,
    parse_error,
    checked_at: promptData.checked_at
  }
}];
